// LoadCarModel loads the simulationCarAlias's CarModel into the .R struct
func (o *SimulationCarAlias) LoadCarModel(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if o == nil {
		return nil
	}

	// Reset the relationship
	o.R.CarModel = nil

	related, err := o.CarModel(mods...).One(ctx, exec)
	if err != nil {
		return err
	}

	related.R.SimulationCarAliases = SimulationCarAliasSlice{o}

	o.R.CarModel = related
	return nil
}

// LoadCarModel loads the simulationCarAlias's CarModel into the .R struct
func (os SimulationCarAliasSlice) LoadCarModel(ctx context.Context, exec bob.Executor, mods ...bob.Mod[*dialect.SelectQuery]) error {
	if len(os) == 0 {
		return nil
	}

	carModels, err := os.CarModel(mods...).All(ctx, exec)
	if err != nil {
		return err
	}

	for _, o := range os {
		if o == nil {
			continue
		}

		for _, rel := range carModels {

			if !(o.CarModelID == rel.ID) {
				continue
			}

			rel.R.SimulationCarAliases = append(rel.R.SimulationCarAliases, o)

			o.R.CarModel = rel
			break
		}
	}

	return nil
}

